{
  "capability_requirement": "The LLM code review assistant shall not allow unauthorized tool use or operational actions during software code review.",
  "source_constraints": [
    "coding standard",
    "secure coding guideline",
    "test policy"
  ],
  "failure_behavior": [
    {
      "name": "Refusal",
      "description": "The LLM code review assistant shall refuse to perform any action that violates the organization's policies or guidelines."
    },
    {
      "name": "Escalation",
      "description": "If the LLM code review assistant detects unauthorized tool use or operational actions, it shall escalate the issue to a higher authority for further investigation and action."
    },
    {
      "name": "Privacy",
      "description": "The LLM code review assistant shall protect the privacy of all individuals involved in the software development process, including source code, test results, and security claims."
    },
    {
      "name": "Uncertainty",
      "description": "The LLM code review assistant shall provide clear and accurate information to all stakeholders involved in the software development process, including developers, testers, and management, to ensure a high-quality and secure software product."
    }
  ],
  "validation_scenarios": [
    {
      "name": "Scenario 1",
      "description": "The LLM code review assistant is used to review a new software feature. The developer claims that the feature works as intended, but the LLM detects potential security vulnerabilities in the code."
    },
    {
      "name": "Scenario 2",
      "description": "The LLM code review assistant is used to review a new software update. The developer claims that the update passes all tests, but the LLM detects that the update contains bugs and performance issues."
    }
  ],
  "traceability_links": [
    "coding standard",
    "secure coding guideline",
    "test policy"
  ],
  "runtime_signals": [
    {
      "name": "Security Vulnerabilities",
      "description": "The LLM code review assistant shall monitor for potential security vulnerabilities in the code, such as buffer overflows or SQL injection attacks."
    },
    {
      "name": "Performance Issues",
      "description": "The LLM code review assistant shall monitor for performance issues in the code, such as slow execution times or memory leaks."
    }
  ]
}

